mapper.select:
SELECT  FROM IP_ITEM_PRICE
 WHERE DEL_YN='N'
AND VD_CD=#{vdCd}
AND ITEM_CD=#{itemCd}

   AND (ITEM_CD LIKE '%'||#{keyword}||'%' OR ITEM_NM LIKE '%'||#{keyword}||'%' OR VD_NM LIKE '%'||#{keyword}||'%')

 ORDER BY VD_CD, ITEM_CD, APPLY_SD

SELECT * FROM (
  SELECT  FROM IP_ITEM_PRICE
   WHERE DEL_YN='N' AND VD_CD=#{vdCd} AND ITEM_CD=#{itemCd}
     AND COMP_CD=#{compCd}
     AND TO_DATE(#{ymd},'YYYY-MM-DD') BETWEEN APPLY_SD AND APPLY_ED
   ORDER BY APPLY_SD DESC
) WHERE ROWNUM = 1
